// pull integrity state independently of the heavy graph payload.
func (r *queryResolver) DocGraphIssues(ctx context.Context) ([]*GraphIssue, error) {
	graph, err := docgraph.BuildGraphWithConfig(r.workingDir(ctx))
	if err != nil {
		return nil, fmt.Errorf("building document graph: %w", err)
	}
	return issuesToGQL(graph.Issues), nil
}

// issuesToGQL converts docgraph.GraphIssue values into the GraphQL model.
// Always returns a non-nil slice so downstream clients can treat an empty
// graph the same as a healthy one (no optional chaining required).
func issuesToGQL(issues []docgraph.GraphIssue) []*GraphIssue {
	out := make([]*GraphIssue, 0, len(issues))
	for _, issue := range issues {
		gql := &GraphIssue{
			IssueID: graphIssueStableID(issue),
			Kind:    string(issue.Kind),
			Message: issue.Message,
		}
		if issue.Path != "" {
			p := issue.Path
			gql.Path = &p
		}
		if issue.ID != "" {
			id := issue.ID
			gql.ID = &id
		}
		if issue.RelatedPath != "" {
			rp := issue.RelatedPath
			gql.RelatedPath = &rp
		}
		out = append(out, gql)
	}
	return out
}

// graphIssueStableID returns a deterministic identifier for a docgraph issue,
// computed from its kind/path/id/relatedPath tuple. The same issue produced by
// two graph builds yields the same ID, which lets the UI pass it back to
// graphRepairIssue without needing the server to remember per-build state.
func graphIssueStableID(issue docgraph.GraphIssue) string {
	payload := strings.Join([]string{
		string(issue.Kind),
		issue.Path,
		issue.ID,
		issue.RelatedPath,
	}, "\x00")
	sum := sha1.Sum([]byte(payload))
	return hex.EncodeToString(sum[:])
}

