// DocumentByPath is the resolver for the documentByPath field.
// It reads the document at the given path (relative to the docgraph root or
// library) and returns its metadata plus raw file content.
func (r *queryResolver) DocumentByPath(ctx context.Context, path string) (*Document, error) {
	if path == "" {
		return nil, fmt.Errorf("path is required")
	}

	wd := r.workingDir(ctx)
	cleaned, err := cleanDocumentPath(wd, path)
	if err != nil {
		return nil, err
	}

	// Prefer the docgraph-tracked location: the documents list surfaces files
	// walked under workingDir, so the detail view must read from the same root
	// (otherwise the URL for a valid list entry 404s).
	if graph, graphErr := docgraph.BuildGraphWithConfig(wd); graphErr == nil {
		if id, ok := graph.PathToID[cleaned]; ok {
			if d, ok := graph.Documents[id]; ok {
				absPath := d.Path
				if !filepath.IsAbs(absPath) {
					absPath = filepath.Join(graph.RootDir, absPath)
				}
				if data, readErr := os.ReadFile(absPath); readErr == nil {
					content := string(data)
					doc := docToGQL(*d)
					doc.Content = &content
					return doc, nil
				}
			}
		}
	}

	// Fall back to the configured library path so documents created via the
	// documentWrite mutation (which target the library) remain readable even
	// when they have no DDx frontmatter and so do not appear in the graph.
	cfg, err := config.LoadWithWorkingDir(wd)
	if err != nil {
		return nil, fmt.Errorf("loading config: %w", err)
	}
	if cfg.Library == nil || cfg.Library.Path == "" {
		return nil, nil
	}
	libPath := cfg.Library.Path
	if !filepath.IsAbs(libPath) {
		libPath = filepath.Join(wd, libPath)
	}

	fullPath := filepath.Join(libPath, cleaned)
	data, err := os.ReadFile(fullPath)
	if err != nil {
		return nil, nil // not found вҶ’ null
	}
	content := string(data)

	return &Document{
		ID:         cleaned,
		Path:       cleaned,
		DependsOn:  []string{},
		Inputs:     []string{},
		Dependents: []string{},
		Content:    &content,
	}, nil
}

func cleanDocumentPath(workingDir, path string) (string, error) {
	cleaned := filepath.Clean(filepath.FromSlash(path))
	if filepath.IsAbs(cleaned) {
		rel, err := filepath.Rel(filepath.Clean(workingDir), cleaned)
		if err != nil {
			return "", fmt.Errorf("invalid path")
		}
		cleaned = rel
	}
	if cleaned == "." || filepath.IsAbs(cleaned) || cleaned == ".." ||
		strings.HasPrefix(cleaned, ".."+string(filepath.Separator)) {
		return "", fmt.Errorf("invalid path")
	}
	return cleaned, nil
}

// Documents is the resolver for the documents field with Relay cursor pagination.
func (r *queryResolver) Documents(ctx context.Context, first *int, after *string, last *int, before *string, typeArg *string) (*DocumentConnection, error) {
	graph, err := docgraph.BuildGraphWithConfig(r.workingDir(ctx))
	if err != nil {
		return nil, fmt.Errorf("building document graph: %w", err)
	}

	docs := graph.AllNodesForOutput()
	sort.Slice(docs, func(i, j int) bool { return docs[i].ID < docs[j].ID })

	// Apply optional type filter by path component.
	if typeArg != nil && *typeArg != "" {
		filtered := docs[:0]
		for _, d := range docs {
			if strings.Contains(d.Path, string([]rune{'/'})+*typeArg+string([]rune{'/'})) ||
				strings.HasPrefix(d.Path, *typeArg+string([]rune{'/'})) {
				filtered = append(filtered, d)
			}
		}
		docs = filtered
	}

	all := make([]*DocumentEdge, len(docs))
	for i, d := range docs {
		all[i] = &DocumentEdge{
			Node:   docToGQL(d),
			Cursor: encodeStableCursor(d.ID),
		}
	}

	startIdx := 0
	if after != nil {
		if afterID, ok := decodeStableCursor(*after); ok {
			for i, e := range all {
				if e.Node.ID == afterID {
					startIdx = i + 1
					break
				}
			}
		}
	}
	endIdx := len(all)
	if before != nil {
		if beforeID, ok := decodeStableCursor(*before); ok {
			for i, e := range all {
				if e.Node.ID == beforeID {
					endIdx = i
					break
				}
			}
		}
	}
	if startIdx > endIdx {
		startIdx = endIdx
	}

	slice := all[startIdx:endIdx]
	if first != nil && *first >= 0 && *first < len(slice) {
		slice = slice[:*first]
	}
	if last != nil && *last >= 0 && *last < len(slice) {
		slice = slice[len(slice)-*last:]
	}

	pageInfo := &PageInfo{
		HasPreviousPage: startIdx > 0,
		HasNextPage:     endIdx < len(all),
	}
	if len(slice) > 0 {
		pageInfo.StartCursor = &slice[0].Cursor
		pageInfo.EndCursor = &slice[len(slice)-1].Cursor
	}

	return &DocumentConnection{
		Edges:      slice,
		PageInfo:   pageInfo,
		TotalCount: len(all),
	}, nil
}

// DocGraph is the resolver for the docGraph field.
func (r *queryResolver) DocGraph(ctx context.Context) (*DocGraph, error) {
	graph, err := docgraph.BuildGraphWithConfig(r.workingDir(ctx))
	if err != nil {
		return nil, fmt.Errorf("building document graph: %w", err)
	}

	docs := graph.AllNodesForOutput()
	sort.Slice(docs, func(i, j int) bool { return docs[i].ID < docs[j].ID })
	gqlDocs := make([]*Document, len(docs))
	for i, d := range docs {
		gqlDocs[i] = docToGQL(d)
	}

	pathToIDJSON, err := json.Marshal(graph.PathToID)
	if err != nil {
		return nil, fmt.Errorf("serializing pathToId: %w", err)
	}
	dependentsJSON, err := json.Marshal(graph.Dependents)
	if err != nil {
		return nil, fmt.Errorf("serializing dependents: %w", err)
	}

	warnings := graph.Warnings
	if warnings == nil {
		warnings = []string{}
	}

	return &DocGraph{
		RootDir:    graph.RootDir,
		Documents:  gqlDocs,
		PathToID:   string(pathToIDJSON),
		Dependents: string(dependentsJSON),
		Warnings:   warnings,
		Issues:     issuesToGQL(graph.Issues),
	}, nil
}

// DocGraphIssues is the resolver for the docGraphIssues field. It returns the
// same structured issue list used by the full graph query so dashboards can
// pull integrity state independently of the heavy graph payload.
func (r *queryResolver) DocGraphIssues(ctx context.Context) ([]*GraphIssue, error) {
	graph, err := docgraph.BuildGraphWithConfig(r.workingDir(ctx))
	if err != nil {
		return nil, fmt.Errorf("building document graph: %w", err)
	}
	return issuesToGQL(graph.Issues), nil
}

// issuesToGQL converts docgraph.GraphIssue values into the GraphQL model.
// Always returns a non-nil slice so downstream clients can treat an empty
// graph the same as a healthy one (no optional chaining required).
func issuesToGQL(issues []docgraph.GraphIssue) []*GraphIssue {
	out := make([]*GraphIssue, 0, len(issues))
	for _, issue := range issues {
		gql := &GraphIssue{
			IssueID: graphIssueStableID(issue),
			Kind:    string(issue.Kind),
			Message: issue.Message,
		}
		if issue.Path != "" {
			p := issue.Path
			gql.Path = &p
		}
		if issue.ID != "" {
			id := issue.ID
			gql.ID = &id
		}
		if issue.RelatedPath != "" {
			rp := issue.RelatedPath
			gql.RelatedPath = &rp
		}
		out = append(out, gql)
	}
	return out
}

// graphIssueStableID returns a deterministic identifier for a docgraph issue,
// computed from its kind/path/id/relatedPath tuple. The same issue produced by
// two graph builds yields the same ID, which lets the UI pass it back to
// graphRepairIssue without needing the server to remember per-build state.

package graphql

import (
	"context"
	"fmt"
	"path/filepath"
	"strings"

	gqlgraphql "github.com/99designs/gqlgen/graphql"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

// RunsStateProvider is the optional sub-interface a StateProvider may
// implement to back the runs/run queries.
// Kept separate from StateProvider so test stubs that don't need runs
// continue to compile.
type RunsStateProvider interface {
	GetRunsGraphQL(projectID string, filter RunFilter) []*Run
	GetRunGraphQL(id string) (*Run, bool)
}

// RunDetailStateProvider is the optional sub-interface for the Story 16
// run-detail surfaces (tool calls + bundle file resolver). Kept separate from
// RunsStateProvider so legacy stubs continue to compile.
type RunDetailStateProvider interface {
	GetRunToolCallsGraphQL(id string) []*RunToolCall
	GetRunBundleFileGraphQL(id, path string) (*RunBundleFileContent, bool)
}

const runDetailViewEventKind = "run_detail_view"
const rawTranscriptViewedEventKind = "raw_transcript_viewed"

// RunFilter holds the optional filter args for Query.runs.
type RunFilter struct {
	Layer   *RunLayer
	BeadID  string
	Status  string
	Harness string
}

// Runs is the resolver for the runs field.
func (r *queryResolver) Runs(ctx context.Context, projectID *string, layer *RunLayer, beadID *string, status *string, harness *string, first *int, after *string) (*RunConnection, error) {
	provider, ok := r.State.(RunsStateProvider)
	if !ok {
		return emptyRunConnection(), nil
	}
	pid := ""
	if projectID != nil {
		pid = *projectID
	}
	filter := RunFilter{Layer: layer}
	if beadID != nil {
		filter.BeadID = *beadID
	}
	if status != nil {
		filter.Status = *status
	}
	if harness != nil {
		filter.Harness = *harness
	}
	all := provider.GetRunsGraphQL(pid, filter)
	return runConnectionFrom(all, first, after), nil
}

// Run is the resolver for the run field.
func (r *queryResolver) Run(ctx context.Context, id string) (*Run, error) {
	provider, ok := r.State.(RunsStateProvider)
	if !ok {
		return nil, nil
	}
	wd := r.workingDir(ctx)
	if wd == "" {
		return nil, nil
	}
	projectID, ok := r.projectIDForWorkingDir(wd)
	if !ok {
		return nil, nil
	}
	run, ok := provider.GetRunGraphQL(id)
	if !ok {
		return nil, nil
	}
	if run.ProjectID == nil || strings.TrimSpace(*run.ProjectID) != projectID {
		return nil, nil
	}
	r.recordRunDetailView(ctx, run)
	if runHasRawTranscriptSelection(ctx) {
		r.recordRawTranscriptViewed(ctx, run)
	}
	return run, nil
}

func (r *queryResolver) projectIDForWorkingDir(workingDir string) (string, bool) {
	if r.State == nil || workingDir == "" {
		return "", false
	}
	for _, proj := range r.State.GetProjectSnapshots(false) {
		if proj.Path == workingDir {
			return proj.ID, true
		}
	}
	return "", false
}

// recordRunDetailView appends the canonical run_detail_view bead audit event
// the first time a project-scoped run detail is resolved for a specific run.
// Duplicate loads of the same run id are ignored, but distinct runs on the
// same bead remain auditable.
func (r *queryResolver) recordRunDetailView(ctx context.Context, run *Run) {
	if run == nil || run.BeadID == nil || strings.TrimSpace(*run.BeadID) == "" {
		return
	}
	if run.ProjectID == nil || strings.TrimSpace(*run.ProjectID) == "" {
		return
	}
	wd := r.workingDir(ctx)
	if wd == "" {
		return
	}
	if projectID, ok := r.projectIDForWorkingDir(wd); !ok || projectID != strings.TrimSpace(*run.ProjectID) {
		return
	}

	store := bead.NewStore(filepath.Join(wd, ".ddx"))
	if existing, err := store.EventsByKind(*run.BeadID, runDetailViewEventKind); err == nil {
		for _, ev := range existing {
			if strings.Contains(ev.Body, "run_id="+run.ID) {
				return
			}
		}
	}

	identity := operatorPromptIdentityInfo{kind: "unknown", actor: "anonymous"}
	if httpReq := httpRequestFromContext(ctx); httpReq != nil {
		identity = operatorPromptIdentity(httpReq)
	}
	body := fmt.Sprintf(
		"project_id=%s run_id=%s layer=%s visibility=project_membership",
		*run.ProjectID,
		run.ID,
		run.Layer,
	)
	_ = store.AppendEvent(*run.BeadID, bead.BeadEvent{
		Kind:    runDetailViewEventKind,
		Summary: "run detail viewed",
		Body:    body,
		Actor:   identity.actor,
		Source:  "graphql:run",
	})
}

func runHasRawTranscriptSelection(ctx context.Context) bool {
	if !gqlgraphql.HasOperationContext(ctx) {
		return false
	}
	for _, field := range gqlgraphql.CollectAllFields(ctx) {
		switch field {
		case "prompt", "response", "stderr":
			return true
		}
	}
	return false
}

func rawTranscriptSelectionSummary(ctx context.Context) string {
	if !gqlgraphql.HasOperationContext(ctx) {
		return ""
	}
	selected := gqlgraphql.CollectAllFields(ctx)
	ordered := make([]string, 0, 3)
	for _, name := range []string{"prompt", "response", "stderr"} {
		for _, field := range selected {
			if field == name {
				ordered = append(ordered, name)
				break
			}
		}
	}
	return strings.Join(ordered, ",")
}

func (r *queryResolver) recordRawTranscriptViewed(ctx context.Context, run *Run) {
	if run == nil || run.BeadID == nil || strings.TrimSpace(*run.BeadID) == "" {
		return
	}
	if run.ProjectID == nil || strings.TrimSpace(*run.ProjectID) == "" {
		return
	}
	wd := r.workingDir(ctx)
	if wd == "" {
		return
	}
	if projectID, ok := r.projectIDForWorkingDir(wd); !ok || projectID != strings.TrimSpace(*run.ProjectID) {
		return
	}

	store := bead.NewStore(filepath.Join(wd, ".ddx"))
	if existing, err := store.EventsByKind(*run.BeadID, rawTranscriptViewedEventKind); err == nil {
		for _, ev := range existing {
			if strings.Contains(ev.Body, "run_id="+run.ID) {
				return
			}
		}
	}

	identity := operatorPromptIdentityInfo{kind: "unknown", actor: "anonymous"}
	if httpReq := httpRequestFromContext(ctx); httpReq != nil {
		identity = operatorPromptIdentity(httpReq)
	}
	fields := rawTranscriptSelectionSummary(ctx)
	if fields == "" {
		fields = "prompt,response,stderr"
	}
	body := fmt.Sprintf(
		"project_id=%s run_id=%s fields=%s visibility=project_membership",
		*run.ProjectID,
		run.ID,
		fields,
	)
	_ = store.AppendEvent(*run.BeadID, bead.BeadEvent{
		Kind:    rawTranscriptViewedEventKind,
		Summary: "raw transcript viewed",
		Body:    body,
		Actor:   identity.actor,
		Source:  "graphql:run",
	})
}

// RunToolCalls is the resolver for the runToolCalls field. Returns the
// normalized tool-call entries persisted at drain time, paginated by
// sequence. Returns an empty connection (not an error) for unknown ids or
// when the backing state provider does not implement RunDetailStateProvider.
func (r *queryResolver) RunToolCalls(ctx context.Context, id string, first *int, after *string) (*RunToolCallConnection, error) {
	provider, ok := r.State.(RunDetailStateProvider)
	if !ok {
		return emptyRunToolCallConnection(), nil
	}
	calls := provider.GetRunToolCallsGraphQL(id)
	return runToolCallConnectionFrom(calls, first, after), nil
}

// RunBundleFile is the resolver for the runBundleFile field. Returns nil
// (not an error) when the path fails canonical-path / whitelist checks or
// the file is not present вҖ” the GraphQL response treats nil as 404.
func (r *queryResolver) RunBundleFile(ctx context.Context, id string, path string) (*RunBundleFileContent, error) {
	provider, ok := r.State.(RunDetailStateProvider)
	if !ok {
		return nil, nil
	}
	out, ok := provider.GetRunBundleFileGraphQL(id, path)
	if !ok {
		return nil, nil
	}
	return out, nil
}

func emptyRunToolCallConnection() *RunToolCallConnection {
	return &RunToolCallConnection{Edges: []*RunToolCallEdge{}, PageInfo: &PageInfo{}, TotalCount: 0}
}

package graphql

import (
	"context"
	"fmt"
	"strings"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	agentlib "github.com/easel/fizeau"
)

var providerStatusCache = struct {
	sync.Mutex
	rows     map[string][]*ProviderStatus
	inFlight map[string]bool
}{
	rows:     make(map[string][]*ProviderStatus),
	inFlight: make(map[string]bool),
}

// harnessRateLimitCache holds the most recently observed rate-limit signal per
// harness name. The server invocation path (or tests) populates it via
// RecordHarnessRateLimit; quotaFromHarnessInfo reads it when the upstream
// HarnessInfo.Quota does not carry token-level ceilings.
var harnessRateLimitCache = struct {
	sync.RWMutex
	byName map[string]agent.RateLimitSignal
}{byName: make(map[string]agent.RateLimitSignal)}

// LookupHarnessRateLimit returns the last-observed signal for a harness, or
// ok=false if none has been recorded.
func LookupHarnessRateLimit(name string) (agent.RateLimitSignal, bool) {
	harnessRateLimitCache.RLock()
	defer harnessRateLimitCache.RUnlock()
	sig, ok := harnessRateLimitCache.byName[name]
	return sig, ok
}

// ProviderStatuses is the resolver for the providerStatuses field.
// It mirrors the output of `legacy agent providers`, annotating each row with
// kind=ENDPOINT, a lastCheckedAt timestamp, and rolling usage derived from
// the sessions index. Quota is populated when the upstream ProviderInfo
// exposes token-level quota headers; null otherwise (FEAT-014 no-fabrication).
func (r *queryResolver) ProviderStatuses(ctx context.Context) ([]*ProviderStatus, error) {
	now := time.Now().UTC()
	entries := r.sessionIndexEntries(ctx)

	if rows := cachedProviderRows(r.workingDir(ctx)); len(rows) > 0 {
		refreshProviderStatuses(r.workingDir(ctx))
		return providerRowsWithUsage(rows, entries, now), nil
	}

	if snapshots, ok, err := agent.ConfiguredProviderSnapshots(r.workingDir(ctx)); err == nil && ok {
		rows := providerStatusesFromInfos(snapshots, entries, now)
		storeProviderRows(r.workingDir(ctx), rows)
		refreshProviderStatuses(r.workingDir(ctx))
		return rows, nil
	} else if err != nil {
		return nil, fmt.Errorf("loading provider snapshots: %w", err)
	}

	// Legacy/global provider config fallback. Bound the synchronous path so the
	// UI can still first-paint harness rows even if provider probing is slow.
	probeCtx, cancel := context.WithTimeout(ctx, 500*time.Millisecond)
	defer cancel()
	providers, err := liveProviderInfos(probeCtx, r.workingDir(ctx))
	if err != nil {
		refreshProviderStatuses(r.workingDir(ctx))
		return []*ProviderStatus{}, nil
	}
	rows := providerStatusesFromInfos(providers, entries, now)
	storeProviderRows(r.workingDir(ctx), rows)
	return rows, nil
}

// HarnessStatuses is the resolver for the harnessStatuses field.
// It returns one row per subprocess harness (kind=HARNESS). Reachability is
// taken from HarnessInfo.Available, rolling usage from the sessions index,
// and quota/auth/model data directly from the upstream HarnessInfo DTO.
func (r *queryResolver) HarnessStatuses(ctx context.Context) ([]*ProviderStatus, error) {
	svc, err := agentlib.New(agentlib.ServiceOptions{})
	if err != nil {
		return []*ProviderStatus{}, nil //nolint:nilerr
	}
	infos, err := svc.ListHarnesses(ctx)
	if err != nil {
		return nil, fmt.Errorf("listing harnesses: %w", err)
	}

	now := time.Now().UTC()
	entries := r.sessionIndexEntries(ctx)
	return harnessStatusesFromInfos(infos, entries, now), nil
}

// DefaultRouteStatus is the resolver for the defaultRouteStatus field.
func (r *queryResolver) DefaultRouteStatus(ctx context.Context) (*DefaultRouteStatus, error) {
	svc, err := agent.NewServiceFromWorkDir(r.workingDir(ctx))
	if err != nil {
		return nil, nil //nolint:nilerr
	}
	dec, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{})
	if err != nil {
		return &DefaultRouteStatus{}, nil //nolint:nilerr
	}
	result := &DefaultRouteStatus{ModelRef: dec.Model}
	if dec.Provider != "" {
		p := dec.Provider
		result.ResolvedProvider = &p
	}
	if dec.Model != "" {
		m := dec.Model
		result.ResolvedModel = &m
	}
	return result, nil
}

// ProviderTrend is the resolver for the providerTrend field.
// It aggregates the sessions index into time buckets for one provider/harness
// and computes a projected-run-out-in-hours callout from the last-24h slope.
func (r *queryResolver) ProviderTrend(ctx context.Context, name string, windowDays int) (*ProviderTrend, error) {
	name = strings.TrimSpace(name)
	if name == "" {
		return nil, fmt.Errorf("name required")
	}
	if windowDays != 7 && windowDays != 30 {
		return nil, fmt.Errorf("windowDays must be 7 or 30")
	}
	now := time.Now().UTC()
	entries := r.sessionIndexEntries(ctx)

	kind, detected := detectProviderOrHarness(ctx, r, name)
	bucketKind := agent.MatchProvider
	if kind == ProviderKindHarness {
		bucketKind = agent.MatchHarness
	}

	bucketSize := time.Hour
	if windowDays > 7 {
		bucketSize = 4 * time.Hour
	}
	buckets := agent.BucketUsage(entries, name, bucketKind, now, windowDays, bucketSize)
	series := make([]*ProviderTrendPoint, 0, len(buckets))
	for _, b := range buckets {
		series = append(series, &ProviderTrendPoint{
			BucketStart: b.Start.UTC().Format(time.RFC3339),
			Tokens:      b.Tokens,
			Requests:    b.Requests,
		})
	}

	trend := &ProviderTrend{
		Name:       name,
		Kind:       kind,
		WindowDays: windowDays,
		Series:     series,
	}

	if detected != nil {
		if ceiling := detected.ceilingTokens; ceiling > 0 {
			c := ceiling
			trend.CeilingTokens = &c
			remaining := detected.remaining
			if remaining < 0 {
				remaining = ceiling - sumTailTokens(buckets, 24)
			}
			if p := projectRunOutHours(buckets, float64(remaining)); p > 0 {
				trend.ProjectedRunOutHours = &p
			}
		}
	}

	return trend, nil
}

// --------- helpers ---------

type detectedRow struct {
	ceilingTokens int
	remaining     int
}

// detectProviderOrHarness looks up a name against providers first, then
// harnesses, returning the resolved kind and quota signal (if any).
func detectProviderOrHarness(ctx context.Context, r *queryResolver, name string) (ProviderKind, *detectedRow) {
	if svc, err := agentlib.New(agentlib.ServiceOptions{}); err == nil {
		harnesses, _ := svc.ListHarnesses(ctx)
		for _, h := range harnesses {
			if strings.EqualFold(h.Name, name) {
				q := quotaFromHarnessInfo(h)
				return ProviderKindHarness, detectedFromQuota(q)
			}
		}
	}
	if snapshots, ok, _ := agent.ConfiguredProviderSnapshots(r.workingDir(ctx)); ok {
		for _, p := range snapshots {
			if strings.EqualFold(p.Name, name) {
				q := quotaFromProviderInfo(p)
				return ProviderKindEndpoint, detectedFromQuota(q)
			}
		}
	}
	if providers, err := liveProviderInfos(ctx, r.workingDir(ctx)); err == nil {
		for _, p := range providers {
			if strings.EqualFold(p.Name, name) {
				q := quotaFromProviderInfo(p)
				return ProviderKindEndpoint, detectedFromQuota(q)
			}
		}
	}
	return ProviderKindEndpoint, nil
}

func detectedFromQuota(q *ProviderQuota) *detectedRow {
	if q == nil {
		return nil
	}
	row := &detectedRow{ceilingTokens: -1, remaining: -1}
	if q.CeilingTokens != nil {
		row.ceilingTokens = *q.CeilingTokens
	}
	if q.Remaining != nil {
		row.remaining = *q.Remaining
	}
	return row
}

// projectRunOutHours returns the hours projected until current headroom is used
// based on the last-24-hour slope of the bucket series. Returns 0 when the
// slope is non-positive, headroom is gone/unknown, or the series is too
// short to estimate.
func projectRunOutHours(buckets []agent.UsageBucket, remaining float64) float64 {
	if len(buckets) < 2 {
		return 0
	}
	// Last 24 hours of buckets; if series is bucketed in 4h blocks, that's 6
	// buckets; 1h buckets gives 24.
	n := 24
	if n > len(buckets) {
		n = len(buckets)
	}
	tail := buckets[len(buckets)-n:]
	tokens := make([]float64, len(tail))
	for i, b := range tail {
		tokens[i] = float64(b.Tokens)
	}
	perBucket := agent.LinearSlope(tokens)
	// Convert slope-per-bucket to slope-per-hour.
	var bucketHours float64
	if len(tail) >= 2 {
		bucketHours = tail[1].Start.Sub(tail[0].Start).Hours()
	}
	if bucketHours <= 0 {
		bucketHours = 1
	}
	perHour := perBucket / bucketHours
	if perHour <= 0 {
		return 0
	}

