import type { PageLoad } from './$types'
import { createClient } from '$lib/gql/client'
import { gql } from 'graphql-request'

const DOC_GRAPH_QUERY = gql`
	query DocGraph {
		docGraph {
			rootDir
			documents {
				id
				path
				title
				dependsOn
				dependents
			}
			pathToId
			warnings
			issues {
				issueId
				kind
				path
				id
				message
				relatedPath
			}
		}
	}
`

const DOC_STALE_QUERY = gql`
	query DocStale {
		docStale {
			id
		}
	}
`

export interface GraphDocument {
	id: string
	path: string
	title: string
	dependsOn: string[]
	dependents: string[]
	staleness: string
	mediaType: string
}

export interface GraphIssue {
	issueId: string
	kind: string
	path: string | null
	id: string | null
	message: string
	relatedPath: string | null
}

interface RawGraphDocument {
	id: string
	path: string
	title: string
	dependsOn: string[]
	dependents: string[]
	staleness?: string
}

interface DocGraph {
	rootDir: string
	documents: RawGraphDocument[]
	pathToId: string
	warnings: string[]
	issues: GraphIssue[]
}

interface DocGraphResult {
	docGraph: DocGraph
}

interface StaleResult {
	docStale: Array<{ id: string }>
}

function mediaTypeFromPath(path: string): string {
	const ext = path.split('.').pop()?.toLowerCase() ?? ''
	if (ext === 'md') return 'text/markdown'
	if (['png', 'jpg', 'jpeg', 'gif', 'webp'].includes(ext)) return 'image/*'
	if (ext === 'svg') return 'image/svg+xml'
	return 'unknown'
}

export const load: PageLoad = async ({ fetch, url }) => {
	const client = createClient(fetch as unknown as typeof globalThis.fetch)

	const [graphData, staleData] = await Promise.all([
		client.request<DocGraphResult>(DOC_GRAPH_QUERY),
		client
			.request<StaleResult>(DOC_STALE_QUERY)
			.catch(() => ({ docStale: [] as Array<{ id: string }> }))
	])

	const graph = graphData.docGraph
	const staleIds = new Set(staleData.docStale.map((s) => s.id))

	let pathToDocId: Record<string, string> = {}
	try {
		pathToDocId = JSON.parse(graph.pathToId ?? '{}')
	} catch {
		pathToDocId = {}
	}

	const documents: GraphDocument[] = graph.documents.map((doc) => ({
		...doc,
		staleness: doc.staleness ?? (staleIds.has(doc.id) ? 'stale' : 'fresh'),
		mediaType: mediaTypeFromPath(doc.path)
	}))

	// Parse initial viewport from URL params
	const zoomParam = parseFloat(url.searchParams.get('zoom') ?? '')
	const panParam = url.searchParams.get('pan')
	const panParts = panParam ? panParam.split(',').map(parseFloat) : null
	const initialTransform =
		!isNaN(zoomParam) && panParts && panParts.length === 2 && panParts.every((v) => !isNaN(v))
			? { x: panParts[0], y: panParts[1], k: zoomParam }
			: null

	const highlightNodeId = url.searchParams.get('highlight') ?? undefined

	return {
		graph: {
			...graph,
			documents,
			pathToDocId,
			issues: graph.issues ?? []
		},
		initialTransform,
		highlightNodeId
	}
}

import type { PageLoad } from './$types';
import { createClient } from '$lib/gql/client';
import { gql } from 'graphql-request';
import { readState } from '$lib/urlState';
import type { GroupBy } from './grouping';

export const ARTIFACTS_QUERY = gql`
	query Artifacts(
		$projectID: ID!
		$first: Int
		$after: String
		$mediaType: String
		$search: String
		$sort: ArtifactSort
		$staleness: String
		$phase: String
		$prefix: [String!]
	) {
		artifacts(
			projectID: $projectID
			first: $first
			after: $after
			mediaType: $mediaType
			search: $search
			sort: $sort
			staleness: $staleness
			phase: $phase
			prefix: $prefix
		) {
			edges {
				node {
					id
					path
					title
					mediaType
					staleness
				}
				cursor
				snippet
			}
			pageInfo {
				hasNextPage
				endCursor
			}
			totalCount
		}
	}
`;

export interface ArtifactNode {
	id: string;
	path: string;
	title: string;
	mediaType: string;
	staleness: string;
}

export interface ArtifactEdge {
	node: ArtifactNode;
	cursor: string;
	snippet?: string | null;
}

export interface PageInfo {
	hasNextPage: boolean;
	endCursor: string | null;
}

export interface ArtifactConnection {
	edges: ArtifactEdge[];
	pageInfo: PageInfo;
	totalCount: number;
}

interface ArtifactsResult {
	artifacts: ArtifactConnection;
}

export const PAGE_SIZE = 50;

export const SORT_OPTIONS = [
	{ value: 'PATH', label: 'Path' },
	{ value: 'TITLE', label: 'Title' },
	{ value: 'MODIFIED', label: 'Last modified' },
	{ value: 'DEPS_COUNT', label: 'Dependency count' },
	{ value: 'ID', label: 'ID' }
] as const;

export type ArtifactSort = (typeof SORT_OPTIONS)[number]['value'];
export const DEFAULT_SORT: ArtifactSort = 'PATH';

const SORT_VALUES = new Set(SORT_OPTIONS.map((o) => o.value));

export function parseSort(raw: string | null): ArtifactSort {
	return raw && SORT_VALUES.has(raw as ArtifactSort) ? (raw as ArtifactSort) : DEFAULT_SORT;
}

export const STALENESS_OPTIONS = ['fresh', 'stale', 'missing'] as const;
export type Staleness = (typeof STALENESS_OPTIONS)[number];
const STALENESS_SET = new Set<string>(STALENESS_OPTIONS);

export function parseStaleness(raw: string | null): Staleness | null {
	return raw && STALENESS_SET.has(raw) ? (raw as Staleness) : null;
}

export const load: PageLoad = async ({ params, url, fetch }) => {
	const state = readState(url.searchParams);
	const hasGroupByParam = url.searchParams.has('groupBy');
	const mediaType = state.mediaType;
	const q = state.q;
	const groupBy: GroupBy = state.groupBy;
	const sort = parseSort(state.sort);
	const staleness = parseStaleness(state.staleness);
	const phase = state.phase;
	const prefix = state.prefix;

	const client = createClient(fetch as unknown as typeof globalThis.fetch);
	const data = await client.request<ArtifactsResult>(ARTIFACTS_QUERY, {
		projectID: params.projectId,
		first: PAGE_SIZE,
		mediaType: mediaType ?? undefined,
		search: q ? q : undefined,
		sort,
		staleness: staleness ?? undefined,
		phase: phase ?? undefined,
		prefix: prefix.length > 0 ? prefix : undefined
	});
	return {
		nodeId: params.nodeId,
		projectId: params.projectId,
		artifacts: data.artifacts,
		mediaType,
		q,
		groupBy,
		sort,
		staleness,
		phase,
		prefix,
		hasGroupByParam
	};
};

